-- ----------------------------------------------------------------------------
-- Customers: Table: Customers
-- ----------------------------------------------------------------------------
CREATE TABLE customers (
  customer_id                         TEXT                 PRIMARY KEY,
  first_name                          TEXT                ,
  last_name                           TEXT                ,
  notes                               TEXT                ,
  status                              TEXT                ,
  owner_email                         TEXT                                      -- Email address of the user who owns this customer record. Used by Row-Level Security to scope visibility to the JWT email of the requester.
);
COMMENT ON TABLE customers IS 'Table: Customers';
COMMENT ON COLUMN customers.owner_email IS 'Email address of the user who owns this customer record. Used by Row-Level Security to scope visibility to the JWT email of the requester.';

-- ----------------------------------------------------------------------------
-- Statuses: Table: Statuses
-- ----------------------------------------------------------------------------
CREATE TABLE statuses (
  statuse_id                          TEXT                 PRIMARY KEY,
  display_name                        TEXT                ,
  description                         TEXT                ,
  is_blocking                         BOOLEAN             ,
  customers                           TEXT                ,
  owner_email                         TEXT                                      -- Email address of the user who owns this status. Used by Row-Level Security to scope visibility.
);
COMMENT ON TABLE statuses IS 'Table: Statuses';
COMMENT ON COLUMN statuses.owner_email IS 'Email address of the user who owns this status. Used by Row-Level Security to scope visibility.';

-- ----------------------------------------------------------------------------
-- AppUsers: Table: AppUsers
-- ----------------------------------------------------------------------------
CREATE TABLE app_users (
  app_user_id                         TEXT                 PRIMARY KEY,
  email_address                       TEXT                ,                     -- Primary identity — matches the JWT email of the signed-in user.
  role                                TEXT                                      -- admin = full access; customer = sees only owned customers (RLS DAG).
);
COMMENT ON TABLE app_users IS 'Table: AppUsers';
COMMENT ON COLUMN app_users.email_address IS 'Primary identity — matches the JWT email of the signed-in user.';
COMMENT ON COLUMN app_users.role IS 'admin = full access; customer = sees only owned customers (RLS DAG).';

